import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Save, Calendar, ShoppingBag, Hash, Receipt, CreditCard, User } from 'lucide-react';

const Lancamento = () => {
  const [form, setForm] = useState({
    descricao: '', 
    valor_total: '', 
    loja: '', 
    pedido: '', 
    nota_fiscal: '', 
    responsavel: '',
    parcelado: false, 
    num_parcelas: 1, 
    data_compra: new Date().toISOString().split('T')[0]
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (parseFloat(form.valor_total) <= 0) {
      alert("O valor deve ser maior que zero!");
      return;
    }

    const { error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: form.parcelado ? parseInt(form.num_parcelas) : 1
      }]);

    if (error) alert("Erro ao salvar: " + error.message);
    else {
      alert("✅ Gasto registrado com sucesso!");
      window.location.reload();
    }
  };

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '20px' }}>Novo Lançamento</h2>
      
      <div className="card">
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '25px' }}>
          
          {/* Linha 1: Data, Loja e Responsável */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
            <div className="input-group">
              <label style={labelStyle}><Calendar size={14} /> Data</label>
              <input type="date" className="form-control" value={form.data_compra} required onChange={e => setForm({...form, data_compra: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><ShoppingBag size={14} /> Loja</label>
              <input placeholder="Ex: Amazon" className="form-control" onChange={e => setForm({...form, loja: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><User size={14} /> Responsável</label>
              <input placeholder="Quem comprou?" className="form-control" onChange={e => setForm({...form, responsavel: e.target.value})} />
            </div>
          </div>

          {/* Linha 2: Descrição (Ocupa tudo) */}
          <div className="input-group">
            <label style={labelStyle}>O que você comprou?</label>
            <input placeholder="Ex: Notebook, Gasolina..." className="form-control" required onChange={e => setForm({...form, descricao: e.target.value})} />
          </div>

          {/* Linha 3: Pedido e NF (Fundo destacado) */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', background: '#f8fafc', padding: '20px', borderRadius: '12px', border: '1px solid var(--border)' }}>
            <div className="input-group">
              <label style={labelStyle}><Hash size={14} /> Nº do Pedido</label>
              <input placeholder="Opcional" className="form-control" onChange={e => setForm({...form, pedido: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><Receipt size={14} /> Nota Fiscal</label>
              <input placeholder="Opcional" className="form-control" onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
            </div>
          </div>

          {/* Linha 4: Financeiro (A Mágica acontece aqui) */}
          <div style={{ display: 'grid', gridTemplateColumns: form.parcelado ? '1fr 1fr 1fr' : '1fr 1fr', gap: '20px', alignItems: 'end' }}>
            
            <div className="input-group">
              <label style={labelStyle}>Valor Total (R$)</label>
              <input type="number" step="0.01" placeholder="0,00" className="form-control" required onChange={e => setForm({...form, valor_total: e.target.value})} />
            </div>

            <div style={{ paddingBottom: '12px' }}>
              <label className="checkbox-container" style={{ background: form.parcelado ? 'var(--primary-light)' : 'transparent', padding: '10px', borderRadius: '8px', transition: '0.3s' }}>
                <input type="checkbox" checked={form.parcelado} onChange={e => setForm({...form, parcelado: e.target.checked})} />
                <span style={{ fontWeight: '600', color: form.parcelado ? 'var(--primary)' : 'inherit' }}>
                  <CreditCard size={14} style={{ marginRight: '5px' }} /> Parcelar?
                </span>
              </label>
            </div>

            {form.parcelado && (
              <div className="input-group fade-in" style={{ animationDuration: '0.3s' }}>
                <label style={labelStyle}>Nº de Parcelas</label>
                <input 
                  type="number" 
                  min="2" 
                  className="form-control" 
                  placeholder="Ex: 12" 
                  required 
                  onChange={e => setForm({...form, num_parcelas: e.target.value})} 
                  style={{ borderColor: 'var(--primary)', borderWidth: '2px' }}
                />
              </div>
            )}
          </div>

          <button type="submit" className="btn-primary" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', height: '55px', marginTop: '10px' }}>
            <Save size={20} /> Finalizar Lançamento
          </button>
        </form>
      </div>
    </div>
  );
};

const labelStyle = { 
  display: 'flex', 
  alignItems: 'center', 
  gap: '8px', 
  fontSize: '0.8rem', 
  fontWeight: '700', 
  color: 'var(--text-muted)', 
  marginBottom: '8px',
  textTransform: 'uppercase',
  letterSpacing: '0.5px'
};

export default Lancamento;
